request.query:
BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT ?port ?portName ?portType WHERE {
  ?peas vocab:NamedElement_name ?peasName .
  FILTER(CONTAINS(LCASE(STR(?peasName)), LCASE("Procedure%20Executive%20and%20Analysis%20Software%20-PEAS"))) .

  # PEAS block is an EncapsulatedClassifier -> it may own ports
  OPTIONAL {
    ?peas rdf:type vocab:EncapsulatedClassifier .
    ?peas vocab:EncapsulatedClassifier_ownedPort ?port .
  }
  OPTIONAL {
    ?port vocab:NamedElement_name ?portName .
  }
  OPTIONAL {
    ?port rdf:type ?portType .
  }
}
LIMIT 25
